        throw new Error(`Log file not found: ${logFilePath}`);
    }

    // Escape the file path for shell safety (prevents command injection)
    const escapedPath = escapeShellArg(logFilePath);

    // Build the shell command as specified
    // 1. grep 'ERROR' - filter lines containing 'ERROR'
    // 2. tail -n 100 - get the last 100 lines (most recent)
    // 3. sort - sort by timestamp (timestamp at beginning of line)
    // 4. tail -n ${entryCount} - get the last N entries
    const command = `grep 'ERROR' ${escapedPath} | tail -n 100 | sort | tail -n ${entryCount}`;

    // Execute the command using shelljs with silent mode (don't echo to console)
    const result = shell.exec(command, { silent: true });

    // Handle command execution results
    // grep returns exit code 1 when no matches are found, which is not an error condition
    if (result.code !== 0 && result.code !== 1) {
        throw new Error(`Command execution failed: ${result.stderr}`);
    }

    // Get trimmed output
    const output = result.stdout.trim();

    // Return empty array if no matches found
    if (!output) {
        return [];
    }

    // Split output by newlines and return as array
    return output.split('\n');
}

module.exports = {extractRecentErrors};
